CREATE PROCEDURE [dbo].[spProductUnitConversionGetById] @UnitConversionId INT AS BEGIN SET NOCOUNT ON; SELECT c.*, fu.UnitCode AS FromUnitCode, fu.UnitName AS FromUnitName, tu.UnitCode AS ToUnitCode, tu.UnitName AS ToUnitName FROM [dbo].[ProductUnitConversion] c INNER JOIN [dbo].[ProductUnit] fu ON fu.UnitId=c.FromUnitId INNER JOIN [dbo].[ProductUnit] tu ON tu.UnitId=c.ToUnitId WHERE c.UnitConversionId=@UnitConversionId; END;
